1205:
SELECT EXISTS (
    SELECT 1
    FROM Laboratory
    WHERE ID = 57266 AND
          (SEX = 'M' AND UA > 8.0 OR SEX = 'F' AND UA > 6.5)
) AS IsNormalRange;

1134:
SELECT (T2.jumping WHERE T1.id = 6) - (T2.jumping WHERE T1.id = 23) AS difference
FROM Player AS T1
JOIN Player_Attributes AS T2 ON T1.player_api_id = T2.player_api_id;

701:
SELECT CAST(SUM(CASE WHEN Score > 50 THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS PercentageAbove50
FROM posts
WHERE OwnerUserId = (SELECT TOP 1 UserId FROM users ORDER BY Reputation DESC);

352:
SELECT CAST(COUNT(CASE WHEN T2.language = 'Chinese Simplified' THEN T1.id ELSE NULL END) AS REAL) * 100 / COUNT(T1.id) AS percentage_chinese_simplified
FROM cards AS T1
JOIN foreign_data AS T2 ON T1.uuid = T2.uuid;

487:
SELECT CAST(SUM(CASE WHEN cardKingdomFoilId IS NOT NULL AND cardKingdomId IS NOT NULL THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS percentage_incredibly_powerful_cards
FROM cards
WHERE setCode = 'Coldsnap';
